        void vechineno()
        {
            string sel1 = "SELECT DISTINCT 0 HRVEHMASTID,'' VEHICLENO FROM DUAL  UNION   SELECT DISTINCT X.HRVEHMASTID,X.VEHICLENO FROM(   SELECT DISTINCT  A.HRVEHMASTID,A.VEHICLENO  FROM HRVEHMAST A  JOIN GTCOMPMAST B ON  A.ACTIVE='T'   JOIN ASPTBLVEHTOKEN C ON C.COMPCODE=B.GTCOMPMASTID  UNION ALL    SELECT  DISTINCT AA.ASPTBLVEHMASID AS HRVEHMASTID,AA.VEHICLENO  FROM ASPTBLVEHMAS AA  JOIN GTCOMPMAST AB ON AA.ACTIVE='T'   JOIN ASPTBLVEHTOKEN AC ON AC.COMPCODE=AB.GTCOMPMASTID   )X  ORDER BY 1";
            DataSet ds = Utility.ExecuteSelectQuery(sel1, "HRVEHMAST");
            DataTable dt = ds.Tables["HRVEHMAST"];
            combovechineno.ValueMember = "HRVEHMASTID";
            combovechineno.DisplayMember = "VEHICLENO";
            combovechineno.DataSource = dt;

        }
        void comboitem()
        {
            try
            {
                string sel1 = "SELECT 0 AS GTGENITEMMASTID, '' AS ITEMNAME FROM DUAL UNION ALL SELECT 1 AS GTGENITEMMASTID, 'TOKEN CANCEL' AS ITEMNAME FROM DUAL UNION ALL  SELECT 2 AS GTGENITEMMASTID, 'ALL' AS ITEMNAME FROM DUAL UNION ALL   SELECT 3 AS GTGENITEMMASTID, 'FULL' AS ITEMNAME FROM DUAL UNION ALL  SELECT DISTINCT  A.GTGENITEMMASTID,A.ITEMNAME FROM GTGENITEMMAST A WHERE A.FT='T' AND A.ACTIVE='T'";
                DataSet ds = Utility.ExecuteSelectQuery(sel1, "GTGENITEMMAST");
                DataTable dt = ds.Tables["GTGENITEMMAST"];
                combocompcode.ValueMember = "GTGENITEMMASTID";
                combocompcode.DisplayMember = "ITEMNAME";
                combocompcode.DataSource = dt;
            }
            catch (Exception EX) { }
        }
